DROP TABLE IF EXISTS `medicines_inventory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `medicines_inventory` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `medicine_name` varchar(255) NOT NULL,
  `quantity_in_packages` int NOT NULL,
  `medicine_type` varchar(100) NOT NULL,
  `expiry_date` date NOT NULL,
  `dosage` varchar(100) DEFAULT NULL,
  `usage_instructions` varchar(255) DEFAULT NULL,
  `added_on` date NOT NULL DEFAULT (curdate()),
  PRIMARY KEY (`id`),
  CONSTRAINT `medicines_inventory_chk_1` CHECK ((char_length(`medicine_name`) > 0)),
  CONSTRAINT `medicines_inventory_chk_2` CHECK ((`quantity_in_packages` >= 0)),
  CONSTRAINT `medicines_inventory_chk_3` CHECK ((`medicine_type` in (_utf8mb4'tablet',_utf8mb4'capsule',_utf8mb4'syrup',_utf8mb4'injection',_utf8mb4'cream',_utf8mb4'other'))),
  CONSTRAINT `medicines_inventory_chk_4` CHECK ((char_length(`dosage`) > 0)),
  CONSTRAINT `medicines_inventory_chk_5` CHECK ((char_length(`usage_instructions`) > 0))
) ENGINE=InnoDB AUTO_INCREMENT=574 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
